reports.query:
with range(1648, 1667) as period
call {
match (r:Field) where r.name = $neodash_field_name
OPTIONAL MATCH (f)-[:SUBFIELD_OF*]->(r)
WITH r, CASE WHEN f IS NOT NULL THEN f ELSE r END AS child
WITH r, collect(child.name) as children
return children + r.name AS fields
}
with period, fields
unwind period as year
call {with year, fields
  // fetch docs written in a given year
  match (d:Document)
  where d.year = year
  with year, count(distinct d) as totYear, fields

  unwind fields as field_name
  optional match (d:Document)-[:TAGGED_WITH]->(f:Field)
  where f.name = field_name and d.year = year
  //with totYear, collect(distinct d) as docInField 
  //with totYear, case when docInField = [] then [null] else docInField end as check
  //unwind check as doc
  with totYear, count(distinct d) as docsInField
  return toFloat(docsInField)/toFloat(totYear) as fracInFieldYear,
  docsInField, totYear as totDocYear
}
with year, fracInFieldYear, docsInField, fields, totDocYear
call {
  with year
  optional match (d:Document)<-[:CITED_IN]-(b:Book)
  where d.year = year 
  with count(distinct d) as tot
  return case when tot<1 then 0.001 else tot end as nCitingYear
}
with year, fracInFieldYear, nCitingYear, fields, docsInField, totDocYear
 // per ogni campo di interesse fetch docs citing nel capo
unwind fields as field_name
optional match (d:Document)<-[:CITED_IN]-(b:Book)-[:TAGGED_WITH]->(f:Field)
where d.year = year and f.name = field_name
//with year, fracInFieldYear, nCitingYear, collect(distinct d) as docsField, docsInField, totDocYear
//with year, fracInFieldYear, nCitingYear, docsInField,totDocYear, case when docsField = [] then [null] else docsField end as check
//unwind check as doc
with year, fracInFieldYear, nCitingYear, count(distinct d) as nCitingInField, docsInField, totDocYear
return year, totDocYear as `Total documents in year`, nCitingInField as `N. documents citing in Field`,fracInFieldYear, docsInField as `N.documents written in Field`, round(nCitingInField/toFloat(nCitingYear),2) as fracCitingInField
order by year

MATCH (p:Person{name:$neodash_person_name})-[:RECEIVED_BY]-(d:Document)-[:TAGGED_WITH]->(f:Tag)
WITH p, f, count(distinct d) AS doc order by doc desc limit 10
return f,p,apoc.create.vRelationship(f, "IN", {weight: toFloat(doc)}, p)
